import React from "react";
import { Navigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext"; // Vérifiez que le chemin d'import est correct

const ProtectedRoute = ({ children }) => {
  const { isAuthenticated } = useAuth(); // Accéder à l'état d'authentification depuis le contexte

  // Vérification que l'état d'authentification est disponible
  if (isAuthenticated === undefined) {
    // Si l'état n'est pas encore chargé (par exemple pendant un chargement), on pourrait afficher un loader ou rien
    return <div>Loading...</div>;
  }

  // Si l'utilisateur n'est pas authentifié, rediriger vers la page de login
  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  // Si l'utilisateur est authentifié, afficher les enfants passés en prop
  return children; // Retourne les enfants (composant) de la route protégée
};

export default ProtectedRoute;
